DROP TABLE IF EXISTS `knowledge_directory`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `knowledge_directory` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '知识目录ID',
  `parent_id` bigint DEFAULT NULL COMMENT '父目录ID',
  `directory_code` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '目录编码',
  `directory_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '目录名称',
  `directory_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'public' COMMENT '目录类型：personal/dept/public/case',
  `case_id` bigint DEFAULT NULL COMMENT '案件ID',
  `dept_id` bigint DEFAULT NULL COMMENT '部门ID',
  `owner_user_id` bigint DEFAULT NULL COMMENT '个人目录所有者',
  `path` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '目录路径',
  `sort_no` int NOT NULL DEFAULT '0' COMMENT '排序',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人ID',
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_knowledge_directory_code` (`directory_code`),
  KEY `idx_knowledge_directory_parent` (`parent_id`),
  KEY `idx_knowledge_directory_case` (`case_id`),
  KEY `idx_knowledge_directory_dept` (`dept_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1638 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='知识库目录表';
