--
-- Table structure for table `wf_definition`
--

DROP TABLE IF EXISTS `wf_definition`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wf_definition` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '流程定义ID',
  `wf_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '流程编码',
  `wf_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '流程名称',
  `wf_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '流程类型：main/subflow',
  `form_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '关联表单编码',
  `version_no` int NOT NULL DEFAULT '1' COMMENT '版本号',
  `enabled` tinyint NOT NULL DEFAULT '1' COMMENT '是否启用：0否 1是',
  `publish_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'draft' COMMENT '发布状态：draft/published/archived',
  `remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `definition_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '流程全局配置JSON',
  `source_wf_id` bigint DEFAULT NULL COMMENT '来源流程定义ID',
  `published_by` bigint DEFAULT NULL COMMENT '发布人ID',
  `published_time` datetime DEFAULT NULL COMMENT '发布时间',
  `immutable_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否不可变版本',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人ID',
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除：0否 1是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_wf_definition_code_version` (`wf_code`,`version_no`),
  KEY `idx_wf_definition_type` (`wf_type`),
  KEY `idx_wf_definition_enabled` (`enabled`)
) ENGINE=InnoDB AUTO_INCREMENT=31019 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='流程定义表';
/*!40101 SET character_set_client = @saved_cs_client */;

